SELECT r.id, r.target_type AS targetType, r.target_id AS targetId, r.reason, r.status, r.handle_remark AS handleRemark, r.created_at AS createdAt, r.handled_at AS handledAt, reporter.id AS reporterId, reporter.username AS reporterName, handler.id AS handlerId, handler.username AS handlerName, CASE r.target_type WHEN 1 THEN (SELECT title FROM posts WHERE id = r.target_id) WHEN 2 THEN (SELECT LEFT(content, 100) FROM comments WHERE id = r.target_id) WHEN 3 THEN (SELECT username FROM users WHERE id = r.target_id) END AS targetSummary FROM reports r JOIN users reporter ON reporter.id = r.user_id LEFT JOIN users handler ON handler.id = r.handler_id
AND r.status = #{status}
AND r.target_type = #{targetType}
ORDER BY r.created_at DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM reports r


        AND r.status = #{status}


        AND r.target_type = #{targetType}
